<template><el-card shadow="never" class="panel"><template #header><div class="header"><span>{{ title }}</span><el-button v-if="retry" link type="primary" @click="$emit('retry')">重试</el-button></div></template><el-alert v-if="error" title="加载失败，可重试" type="warning" :closable="false" show-icon/><el-empty v-else-if="!items.length" description="暂无事项" :image-size="48"/><el-scrollbar v-else max-height="230"><div v-for="item in items" :key="item.id" class="item"><div><strong>{{ item.title }}</strong><p>{{ item.meta }}</p></div><el-button v-if="item.to" link type="primary" @click="$router.push(item.to)">查看</el-button></div></el-scrollbar></el-card></template>
<script setup>defineProps({title:String,items:{type:Array,default:()=>[]},error:Boolean,retry:Boolean});defineEmits(['retry'])</script>
<style scoped>.panel{border-radius:var(--radius-large)}.header,.item{display:flex;justify-content:space-between;align-items:center}.item{padding:10px 0;border-bottom:1px solid var(--color-border)}.item:last-child{border-bottom:0}.item strong{font-size:14px}.item p{font-size:12px;color:var(--color-ink-muted);margin-top:3px}</style>
